    // fgets reads up to buffer_size - 1 characters or until a newline or EOF is encountered.
    // It stores the newline character if there is space.
    if (fgets(buffer, (int)buffer_size, stdin) == NULL) {
        fprintf(stderr, "Error: Failed to read from stdin.\n");
        return -1;
    }

    // Check for and remove the trailing newline character, if present.
    // strchr finds the first occurrence of '\n'.
    char *newline_pos = strchr(buffer, '\n');
